void insert(Token.Comment commentToken) {
    Comment comment = new Comment(commentToken.getData());
    Node insert = comment;
    if (commentToken.bogus) {
        String data = comment.getData();
        if (!data.startsWith("!") || data.length() <= 1) {
            return;
        }
    }
    if (insert == null) {
        return;
    }
    insertNode(insert);
}
